mapper.select:
SELECT s.id, s.name, s.subtitle, s.main_image AS mainImage, c.name AS categoryName, b.name AS brandName, (SELECT MIN(sk.price) FROM sku sk WHERE sk.spu_id = s.id AND sk.deleted = 0) AS minPrice, s.sales, s.status FROM spu s LEFT JOIN category c ON c.id = s.category_id LEFT JOIN brand b ON b.id = s.brand_id WHERE s.deleted = 0
AND s.name LIKE CONCAT('%', #{keyword}, '%')
AND s.category_id = #{categoryId}
AND s.brand_id = #{brandId}
ORDER BY s.create_time DESC
